 DECLARE          table_exists number;       v_start_time timestamp(6);        v_end_time timestamp(6);       v_payroll_submit_cnt number ;       v_tot_err_cnt number ;       v_distinct_err_type_cnt number;   v_start_time_pst timestamp(6);   v_end_time_pst timestamp(6);   BEGIN      select (SYSTIMESTAMP-1) into v_start_time_pst from dual;   select (SYSTIMESTAMP-16/24) into v_start_time from dual;         select  (SYSTIMESTAMP+8/24) into v_end_time from dual;   select  (SYSTIMESTAMP) into v_end_time_pst from dual;          SELECT /*+ index (sst PSP_SOURCE_SYSTEM_TRANSMIS_I2) */ COUNT (*)  into           v_payroll_submit_cntFROM PSP_LOCAL.psp_source_system_transmission sst    WHERE     from_source_system = 'QBDT'          AND TYPE = 'PayrollSubmission'          AND created_date BETWEEN v_start_time and v_end_time;                       SELECT /*+ index (SST PSP_SOURCE_SYSTEM_TRANSMIS_I2 ) */ COUNT (             DISTINCT SUBSTR (                         CAST (                            REGEXP_SUBSTR (SST.RESPONSE_DOCUMENT,                                           'Message Code[^,]*]') AS VARCHAR (17)),                         1,                         17)) ,count(*) into v_distinct_err_type_cnt, v_tot_err_cnt     FROM PSP_LOCAL.psp_source_system_transmission SST    WHERE     FROM_SOURCE_SYSTEM = 'QBDT'          AND TYPE = 'PayrollSubmission'          AND created_date BETWEEN v_start_time and v_end_time          AND description = 'Error' and  SUBSTR (                         CAST (                            REGEXP_SUBSTR (SST.RESPONSE_DOCUMENT,                                           'Message Code[^,]*]') AS VARCHAR (17)),                         1,                         17) in ('Message Code 2002',   'Message Code 3004',   'Message Code 2102',   'Message Code 2001',   'Message Code 2106',   'Message Code 2205',   'Message Code 9000',   'Message Code 2108',   'Message Code 2202',   'Message Code 2107') ;            dbms_output.put_line('************************************** PAYROLL STATS FOR THE LAST 24 HRS ***************************************');   dbms_output.put_line('                                                                                                                ');   dbms_output.put_line('                                                                                                                ');   dbms_output.put_line('                                                                                                                ');   dbms_output.put_line('THE BELOW STATS ARE FOR THE PAYROLL SUBMITS BETWEEN '|| v_start_time_pst || ' PST AND '||v_end_time_pst ||' PST');   dbms_output.put_line('                                                                                                                ');   dbms_output.put_line('                                                                                                                ');   dbms_output.put_line('Total Payroll Submit requests received : ' ||trunc(v_payroll_submit_cnt));   dbms_output.put_line('Total Error Count :'||trunc(v_tot_err_cnt));   dbms_output.put_line('Distinct Error Types :'||trunc(v_distinct_err_type_cnt));   dbms_output.put_line('                                                                                                                ');   dbms_output.put_line('                                                                                                                ');   dbms_output.put_line('                                                                                                                ');   dbms_output.put_line('*****************************************************************************************************************');   commit;   END;                